<script setup lang="ts">
withDefaults(defineProps<{
  size?: number
  state?: 'idle' | 'thinking' | 'celebrating' | 'subtle'
  visible?: boolean
}>(), {
  size: 64,
  state: 'idle',
  visible: true,
})
